DROP DATABASE IF EXISTS school;
CREATE DATABASE school;
USE school;

-- Users --
CREATE TABLE Users (user_id INT AUTO_INCREMENT PRIMARY KEY, f_Name VARCHAR(30) NOT NULL, l_Name VARCHAR(30) NOT NULL, role VARCHAR(10) NOT NULL, password VARCHAR(200) NOT NULL);
ALTER TABLE Users AUTO_INCREMENT = 620000000;

-- Insert Users --

-- Admin --
CREATE TABLE Admin (Admin_Id INT PRIMARY KEY, FOREIGN KEY (Admin_Id) REFERENCES Users(user_id) ON DELETE CASCADE);

-- Insert Admin --

-- Lecturer --
CREATE TABLE Lecturer (Lect_Id INT PRIMARY KEY, Department VARCHAR(30), FOREIGN KEY (Lect_Id) REFERENCES Users(user_id) ON DELETE CASCADE);

-- Student --
CREATE TABLE Student (Std_Id INT PRIMARY KEY, DOB DATE, FOREIGN KEY (Std_Id) REFERENCES Users(user_id) ON DELETE CASCADE);

-- Course --
CREATE TABLE Course (Course_Id VARCHAR(255) PRIMARY KEY, C_Title VARCHAR(255));

-- Insert Course

-- Teaches --
CREATE TABLE Teaches (Lect_Id INT, Course_Id VARCHAR(255), PRIMARY KEY (Lect_Id, Course_Id), FOREIGN KEY (Lect_Id) REFERENCES Lecturer(Lect_Id), FOREIGN KEY (Course_Id) REFERENCES Course(Course_Id));

-- Insert Teaches --

-- Assignment --
CREATE TABLE Assignment (Assign_Id INT PRIMARY KEY, Course_Id VARCHAR(255), Assign_Title VARCHAR(255), FOREIGN KEY (Course_Id) REFERENCES Course(Course_Id));

-- Insert Assignment --

-- Enrols --
CREATE TABLE Enrols (Std_Id INT, Course_Id VARCHAR(255), Grade INT DEFAULT NULL, PRIMARY KEY (Std_Id, Course_Id), FOREIGN KEY (Std_Id) REFERENCES Student(Std_Id), FOREIGN KEY (Course_Id) REFERENCES Course(Course_Id));

-- Submits --
CREATE TABLE Submits (Std_Id INT, Assign_Id INT, Assign_grade INT DEFAULT NULL, submit_time DATE, submission VARCHAR(255), PRIMARY KEY (Std_Id, Assign_Id), FOREIGN KEY (Std_Id) REFERENCES Student(Std_Id), FOREIGN KEY (Assign_Id) REFERENCES Assignment(Assign_Id));

-- Insert Submits --

-- Insert Enrols --

-- Discussion_Forum --
CREATE TABLE Discussion_Forum (Forum_Id INT PRIMARY KEY, Course_Id VARCHAR(255), Forum_Title VARCHAR(255), FOREIGN KEY (Course_Id) REFERENCES Course(Course_Id));

-- Discussion_Thread --
CREATE TABLE Discussion_Thread (Thread_Id INT PRIMARY KEY, Forum_Id INT, date Date, FOREIGN KEY (Forum_Id) REFERENCES Discussion_Forum(Forum_Id));

-- Generates --
CREATE TABLE Generates (Std_Id INT, Thread_Id INT PRIMARY KEY, FOREIGN KEY (Std_Id) REFERENCES Student(Std_Id), FOREIGN KEY (Thread_Id) REFERENCES Discussion_Thread(Thread_Id));

-- Creates --
CREATE TABLE Creates (Admin_Id INT, Course_Id VARCHAR(255), PRIMARY KEY (Admin_Id, Course_Id), FOREIGN KEY (Course_Id) REFERENCES Course(Course_Id));

-- Topic --
CREATE TABLE Topic (Topic_Id INT PRIMARY KEY, Course_Id VARCHAR(255), Topic_Title VARCHAR(255), FOREIGN KEY (Course_Id) REFERENCES Course(Course_Id));

-- Content --
CREATE TABLE Content (Content_Id INT PRIMARY KEY, Topic_Id INT, link VARCHAR(255), file VARCHAR(255), slide VARCHAR(255), FOREIGN KEY (Topic_Id) REFERENCES Topic(Topic_Id));

-- Events --
CREATE TABLE Events (Event_Id INT PRIMARY KEY, Course_Id VARCHAR(255), Start_Date DATE, End_Date DATE, Event_Title VARCHAR(255), FOREIGN KEY (Course_Id) REFERENCES Course(Course_Id));
